<template>
  <el-dropdown
    :class="{ invisible: viewMode && !dropdownShowName }"
    :disabled="!dropdownOptions.length || viewMode"
    :trigger="trigger"
    class="dropdown-select"
    @command="handleCommand"
    @visible-change="handleVisibleChange"
  >
    <div class="dropdown-trigger">
      <div v-if="dropdownName" class="dropdown-name">
        {{ dropdownShowName || dropdownName }}
        <i
          v-if="!viewMode"
          class="el-icon-arrow-down dropdown-arrow"
          :class="{ 'is-open': dropdownVisible }"
        ></i>
      </div>
      <slot v-else></slot>
    </div>
    <el-dropdown-menu slot="dropdown" class="dropdown-select-menu">
      <el-dropdown-item
        v-for="option in dropdownOptions"
        :key="option[dropdownItem.value]"
        :command="option"
        :class="{ 'is-active': value == option[dropdownItem.value] }"
        class="dropdown-select-item"
      >
        <svg
          v-if="value !== undefined"
          width="14"
          height="14"
          viewBox="0 0 14 14"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          class="dropdown-check-icon"
          :class="{ 'is-visible': value == option[dropdownItem.value] }"
        >
          <path
            fill-rule="evenodd"
            clip-rule="evenodd"
            d="M11.0683 2.15625H14L4.75474 12.1007L0 6.12014H2.74297L4.88192 8.81054L11.0683 2.15625Z"
            fill="#409EFF"
          />
        </svg>
        {{ option[dropdownItem.label] }}
      </el-dropdown-item>
    </el-dropdown-menu>
  </el-dropdown>
</template>

<script>
export default {
  name: 'DropdownSelect',
  props: {
    value: {
      type: [String, Number],
      default: undefined
    },
    dropdownName: {
      type: String,
      default: ''
    },
    dropdownOptions: {
      type: Array,
      required: true
    },
    dropdownItem: {
      type: Object,
      default: () => ({
        label: 'label',
        value: 'value'
      })
    },
    defaultValueIndex: {
      type: [Number, String],
      default: undefined
    },
    trigger: {
      type: String,
      default: 'hover'
    },
    viewMode: {
      type: Boolean,
      default: false
    }
  },
  data () {
    return {
      dropdownShowName: '',
      dropdownVisible: false
    }
  },
  watch: {
    dropdownOptions: {
      handler (newValue, oldValue) {
        if ((oldValue && oldValue.length) || (newValue && newValue.length)) {
          if (this.viewMode) {
            const selectItem = this.dropdownOptions.find(
              (item) => item[this.dropdownItem.value] == this.value
            )
            if (selectItem) {
              this.dropdownShowName = selectItem[this.dropdownItem.label]
            }
          } else if (this.defaultValueIndex > -1) {
            this.handleCommand(this.dropdownOptions[Number(this.defaultValueIndex)])
          }
          this._unwatchDefaultOptions && this._unwatchDefaultOptions()
          this._unwatchDefaultOptions = null
        }
      },
      immediate: true,
      deep: true
    },
    value: {
      handler () {
        if (this.viewMode) {
          const selectItem = this.dropdownOptions.find(
            (item) => item[this.dropdownItem.value] == this.value
          )
          this.dropdownShowName = selectItem ? selectItem[this.dropdownItem.label] : ''
        }
      },
      immediate: true
    }
  },
  methods: {
    handleCommand (optionItem) {
      this.dropdownShowName = optionItem[this.dropdownItem.label]
      this.$emit('input', optionItem[this.dropdownItem.value])
      this.$emit('change', optionItem, optionItem[this.dropdownItem.value])
    },
    handleVisibleChange (visible) {
      this.dropdownVisible = visible
    }
  }
}
</script>

<style scoped>
.dropdown-select {
  display: inline-block;
}

.dropdown-select.invisible {
  visibility: hidden;
}

.dropdown-trigger {
  cursor: pointer;
}

.dropdown-name {
  display: flex;
  align-items: center;
  font-weight: 600;
  color: #303133;
  line-height: 32px;
}

.dropdown-arrow {
  margin-left: 6px;
  font-size: 14px;
  color: #535d6e;
  transition: transform 0.2s;
}

.dropdown-arrow.is-open {
  transform: rotate(180deg);
}

.dropdown-select-menu {
  padding: 4px;
}

.dropdown-select-item {
  display: flex;
  align-items: center;
  padding: 8px;
  border-radius: 3px;
  gap: 9px;
}

.dropdown-select-item.is-active {
  background: #f4f5f9;
}

.dropdown-check-icon {
  visibility: visible;
  opacity: 0;
  flex-shrink: 0;
}

.dropdown-check-icon.is-visible {
  opacity: 1;
}
</style>
