<template>
  <div class="element-patch-demo">
    <el-alert
      type="info"
      :closable="false"
      show-icon
      title="Element UI 扩展说明"
      description="补丁在 main.js 启动时注入。el-menu 垂直缩进改为每级 8px；el-image 通过 $attrs 扩展预览行为（非 Element UI 原生 prop）。"
      class="patch-alert"
    />

    <el-alert
      type="warning"
      :closable="false"
      show-icon
      title="el-image 扩展属性命名注意"
      class="patch-alert"
    >
      <p class="attr-hint-intro">以下 3 个为<strong>补丁扩展</strong>，不是 Element UI 文档里的 prop。模板写法与补丁读取的 <code>$attrs</code> 键名必须一致，统一用 <strong>camelCase</strong>：</p>
      <ul class="attr-hint-list">
        <li v-for="item in patchAttrHints" :key="item.key">
          <code>{{ item.key }}</code>（{{ item.type }}）— {{ item.desc }}
          <span class="attr-example">正确：{{ item.example }}</span>
        </li>
      </ul>
      <p class="attr-wrong-title">错误写法（补丁读不到，控制台会 warning）：</p>
      <ul class="attr-hint-list attr-wrong-list">
        <li v-for="item in patchAttrWrong" :key="item.wrong">
          <code>{{ item.wrong }}</code> → 应改为 <code>{{ item.correct }}</code>
        </li>
      </ul>
    </el-alert>

    <div class="demo-block">
      <div class="demo-label">1. el-menu 缩进改造（每级 +8px）</div>
      <div class="menu-compare">
        <div class="menu-compare-item">
          <div class="compare-caption">改造前（Element UI 默认）</div>
          <img :src="menuDefaultImg" class="menu-ref-img" alt="改造前菜单缩进" />
        </div>
        <div class="menu-compare-item">
          <div class="compare-caption">改造后（当前项目，每级 8px）</div>
          <div class="menu-demo-wrap">
            <el-menu
              default-active="order-list"
              class="patch-menu"
              background-color="#304156"
              text-color="#bfcbd9"
              active-text-color="#409EFF"
            >
              <el-submenu index="mall">
                <template slot="title">
                  <i class="el-icon-s-shop"></i>
                  <span>商城管理</span>
                </template>
                <el-submenu index="goods">
                  <template slot="title">商品中心</template>
                  <el-menu-item index="goods-list">商品列表</el-menu-item>
                  <el-menu-item index="goods-category">类目管理</el-menu-item>
                </el-submenu>
                <el-menu-item index="order-list">
                  <i class="el-icon-s-order"></i>
                  <span>订单管理</span>
                </el-menu-item>
              </el-submenu>
              <el-submenu index="marketing">
                <template slot="title">
                  <i class="el-icon-present"></i>
                  <span>营销中心</span>
                </template>
                <el-menu-item index="coupon">优惠券</el-menu-item>
                <el-menu-item index="seckill">限时秒杀</el-menu-item>
              </el-submenu>
              <el-menu-item index="settings">
                <i class="el-icon-setting"></i>
                <span>系统设置</span>
              </el-menu-item>
            </el-menu>
          </div>
        </div>
      </div>
    </div>

    <div class="demo-block">
      <div class="demo-label">2. el-image 默认预览（6 张，可循环切换）</div>
      <div class="image-grid">
        <el-image
          v-for="(url, index) in previewList"
          :key="'default-' + index"
          class="thumb-image"
          :src="url"
          fit="cover"
          :preview-src-list="previewList"
        />
      </div>
    </div>

    <div class="demo-block">
      <div class="demo-label">3. noInfinite — 禁止首尾循环</div>
      <div class="image-grid">
        <el-image
          v-for="(url, index) in previewList"
          :key="'noinf-' + index"
          class="thumb-image"
          :src="url"
          fit="cover"
          :preview-src-list="previewList"
          noInfinite
        />
      </div>
      <pre class="usage-code">&lt;el-image :preview-src-list="list" noInfinite /&gt;</pre>
    </div>

    <div class="demo-block">
      <div class="demo-row-2">
        <div class="demo-row-item">
          <div class="demo-label">4. fullMode — 打开时铺满视口</div>
          <el-image
            class="thumb-image thumb-image--large"
            :src="previewList[0]"
            fit="cover"
            :preview-src-list="previewList"
            fullMode
          />
          <pre class="usage-code">&lt;el-image :preview-src-list="list" fullMode /&gt;</pre>
        </div>
        <div class="demo-row-item">
          <div class="demo-label">5. viewerRotate — 默认旋转 180°</div>
          <el-image
            class="thumb-image thumb-image--large"
            :src="previewList[1]"
            fit="cover"
            :preview-src-list="[previewList[1]]"
            :viewerRotate="180"
          />
          <pre class="usage-code">&lt;el-image :preview-src-list="[url]" :viewerRotate="180" /&gt;</pre>
        </div>
      </div>
    </div>

    <div class="demo-block">
      <div class="demo-label">6. fullMode + viewerRotate + noInfinite</div>
      <div class="image-grid">
        <el-image
          v-for="(url, index) in previewList"
          :key="'combo-' + index"
          class="thumb-image"
          :src="url"
          fit="cover"
          :preview-src-list="previewList"
          fullMode
          noInfinite
          :viewerRotate="180"
        />
      </div>
      <pre class="usage-code">&lt;el-image
  :preview-src-list="list"
  fullMode
  noInfinite
  :viewerRotate="180"
/&gt;</pre>
    </div>
  </div>
</template>

<script>
import { IMAGE_PATCH_ATTR_HINTS, IMAGE_PATCH_ATTR_WRONG } from '@/utils/elementUiPatches'

const previewList = [
  require('@/assets/images/map/m_7_1.jpg'),
  require('@/assets/images/map/m_7_2.jpg'),
  require('@/assets/images/map/m_7_3.jpg'),
  require('@/assets/images/map/m_8_1.jpg'),
  require('@/assets/images/map/m_8_2.jpg'),
  require('@/assets/images/map/m_8_3.jpg')
]

export default {
  name: 'ElementUiPatchDemo',
  data () {
    return {
      menuDefaultImg: require('@/assets/images/menu_default.png'),
      previewList,
      patchAttrHints: IMAGE_PATCH_ATTR_HINTS,
      patchAttrWrong: IMAGE_PATCH_ATTR_WRONG
    }
  }
}
</script>

<style scoped>
.element-patch-demo {
  padding: 12px 16px 32px;
}

.patch-alert {
  margin-bottom: 16px;
}

.attr-hint-intro {
  margin: 0 0 8px;
  font-size: 13px;
  line-height: 1.6;
}

.attr-hint-list {
  margin: 0 0 8px;
  padding-left: 20px;
  font-size: 13px;
  line-height: 1.8;
}

.attr-example {
  display: block;
  color: #909399;
  font-size: 12px;
  margin-top: 2px;
}

.attr-wrong-title {
  margin: 8px 0 4px;
  font-size: 13px;
}

.attr-wrong-list {
  color: #e6a23c;
}

.demo-block {
  margin-bottom: 28px;
  padding-bottom: 24px;
  border-bottom: 1px dashed #ebeef5;
}

.demo-block:last-child {
  border-bottom: none;
}

.demo-label {
  font-size: 15px;
  font-weight: 600;
  color: #303133;
  margin-bottom: 12px;
}

.demo-row-2 {
  display: flex;
  flex-wrap: wrap;
  gap: 32px;
}

.demo-row-item {
  flex: 1;
  min-width: 260px;
}

.menu-compare {
  display: flex;
  flex-wrap: wrap;
  gap: 24px;
  align-items: flex-start;
}

.menu-compare-item {
  flex-shrink: 0;
}

.compare-caption {
  font-size: 13px;
  color: #606266;
  margin-bottom: 8px;
}

.menu-ref-img {
  display: block;
  width: 240px;
  border: 1px solid #ebeef5;
  border-radius: 4px;
}

.menu-demo-wrap {
  width: 240px;
  border-radius: 4px;
  overflow: hidden;
  border: 1px solid #ebeef5;
}

.patch-menu {
  border-right: none;
}

.image-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
}

.thumb-image {
  width: 120px;
  height: 80px;
  border-radius: 4px;
  cursor: pointer;
  border: 1px solid #ebeef5;
}

.thumb-image--large {
  width: 200px;
  height: 133px;
}

.usage-code {
  margin-top: 12px;
  padding: 10px 12px;
  background: #f5f7fa;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.6;
  color: #303133;
  overflow-x: auto;
}
</style>
