<template>
  <el-pagination
    :current-page="page"
    :page-size="limit"
    :total="total"
    :page-sizes="pageSizes"
    layout="total, sizes, prev, pager, next, jumper"
    background
    @size-change="onSizeChange"
    @current-change="onPageChange"
  />
</template>

<script>
export default {
  name: 'Pagination',
  props: {
    total: {
      type: Number,
      default: 0
    },
    page: {
      type: Number,
      default: 1
    },
    limit: {
      type: Number,
      default: 10
    },
    pageSizes: {
      type: Array,
      default: () => [10, 20, 50, 100]
    }
  },
  methods: {
    onSizeChange (size) {
      this.$emit('update:limit', size)
      this.$emit('pagination')
    },
    onPageChange (page) {
      this.$emit('update:page', page)
      this.$emit('pagination')
    }
  }
}
</script>
