/** 表格弹窗等演示用 Mock 数据（电商场景） */

const PRODUCT_NAMES = [
  '无线蓝牙耳机 Pro', '极简运动水杯', '纯棉圆领 T 恤', '轻薄防晒外套',
  '智能手环 S2', '北欧风台灯', '保湿面膜 10 片装', '便携榨汁杯',
  '儿童积木套装', '真丝眼罩', '机械键盘 K87', '瑜伽垫 6mm',
  '不锈钢保温杯', '香薰加湿器', '跑步腰包', '桌面收纳盒'
]

const CATEGORIES = ['数码', '服饰', '家居', '美妆']

const MOCK_ITEMS = Array.from({ length: 56 }, (_, i) => ({
  id: i + 1,
  sku: `SKU${String(10001 + i)}`,
  name: `${PRODUCT_NAMES[i % PRODUCT_NAMES.length]}-${String(i + 1).padStart(2, '0')}`,
  category: CATEGORIES[i % CATEGORIES.length],
  stock: Math.floor(Math.random() * 900) + 20,
  price: (Math.random() * 499 + 29).toFixed(2),
  onSale: i % 6 !== 0
}))

export function mockTableQueryApi (params) {
  return new Promise((resolve) => {
    setTimeout(() => {
      let filtered = MOCK_ITEMS.slice()
      if (params.name) {
        const kw = String(params.name).trim().toLowerCase()
        filtered = filtered.filter((item) => item.name.toLowerCase().includes(kw))
      }
      if (params.category) {
        filtered = filtered.filter((item) => item.category === params.category)
      }
      const pageNo = params.pageNo || 1
      const pageSize = params.pageSize || 10
      const start = (pageNo - 1) * pageSize
      resolve({
        list: filtered.slice(start, start + pageSize),
        total: filtered.length
      })
    }, 280)
  })
}

