<template>
  <el-dialog :title="title"
             :width="width"
             :visible.sync="dialogVisible"
             :before-close="handleClose"
             append-to-body
             class="common-select-table-dialog">
    <el-tabs v-model="activeTab"
             type="card"
             class="dialog-tabs">
      <el-tab-pane label="选择数据"
                   name="select">
        <div class="query-form-wrap">
          <el-form :model="queryParams"
                   inline>
            <slot name="query"
                  :params="queryParams"></slot>
            <el-form-item>
              <el-button type="primary"
                         @click="handleQuery">搜索</el-button>
              <el-button @click="handleReset">重置</el-button>
            </el-form-item>
          </el-form>
        </div>

        <div class="table-wrap">
          <el-table ref="tableRef"
                    v-loading="loading"
                    :data="list"
                    stripe
                    :row-key="rowKey"
                    :row-class-name="rowClassName"
                    @select="handleSelect"
                    @select-all="handleSelectAll"
                    @row-click="handleRowClick">
            <el-table-column v-if="multiple"
                             type="selection"
                             width="55"
                             fixed="left" />
            <el-table-column v-else
                             width="55"
                             fixed="left">
              <template slot-scope="scope">
                <div class="single-radio-cell"
                     @click.stop="onSingleRadioCellClick(scope.row)">
                  <el-radio :value="selectedRowKey"
                            :label="scope.row[rowKey]"
                            :disabled="isRowDisabled(scope.row)"
                            @click.native.stop="selectSingleRow(scope.row)">&nbsp;</el-radio>
                </div>
              </template>
            </el-table-column>
            <template v-for="(column, index) in tableColumns">
              <el-table-column :key="column.prop || index"
                               :prop="column.prop"
                               :label="column.label"
                               :align="column.align || 'center'"
                               :width="column.width"
                               :min-width="column.minWidth"
                               :fixed="column.fixed"
                               :show-overflow-tooltip="!column.slot">
                <template slot-scope="scope">
                  <slot v-if="column.slot"
                        :name="column.slot"
                        :row="scope.row"></slot>
                  <span v-else>{{ getCellText(scope.row, column) }}</span>
                </template>
              </el-table-column>
            </template>
          </el-table>
        </div>

        <div class="pagination-wrap">
          <Pagination :total="total"
                      :page.sync="queryParams.pageNo"
                      :limit.sync="queryParams.pageSize"
                      @pagination="getList" />
        </div>
      </el-tab-pane>

      <el-tab-pane :label="`已选数据 ${innerSelectedList.length} 条`"
                   name="selected">
        <div class="selected-toolbar">
          <el-button type="danger"
                     :disabled="!innerSelectedList.length"
                     @click="handleClearSelected">
            清空选择
          </el-button>
        </div>

        <el-table :data="innerSelectedList"
                  stripe>
          <template v-for="(column, index) in tableColumns">
            <el-table-column :key="'sel-' + (column.prop || index)"
                             :prop="column.prop"
                             :label="column.label"
                             :align="column.align || 'center'"
                             :width="column.width"
                             :min-width="column.minWidth"
                             :show-overflow-tooltip="!column.slot">
              <template slot-scope="scope">
                <slot v-if="column.slot"
                      :name="column.slot"
                      :row="scope.row"></slot>
                <span v-else>{{ getCellText(scope.row, column) }}</span>
              </template>
            </el-table-column>
          </template>
          <el-table-column label="操作"
                           width="80"
                           fixed="right">
            <template slot-scope="scope">
              <el-button type="text"
                         style="color: #f56c6c;"
                         @click="handleRemoveSelected(scope.row)">
                删除
              </el-button>
            </template>
          </el-table-column>
        </el-table>
      </el-tab-pane>
    </el-tabs>

    <div slot="footer"
         class="dialog-footer">
      <el-button type="primary"
                 @click="handleConfirm">确认</el-button>
      <el-button @click="dialogVisible = false">取消</el-button>
    </div>
  </el-dialog>
</template>

<script>
import Pagination from '@/components/Pagination.vue'

export default {
  name: 'CommonSelectTableDialog',
  components: { Pagination },
  props: {
    title: {
      type: String,
      default: '选择数据'
    },
    width: {
      type: [String, Number],
      default: '60%'
    },
    multiple: {
      type: Boolean,
      default: true
    },
    tableColumns: {
      type: Array,
      required: true
    },
    queryApi: {
      type: Function,
      required: true
    },
    rowKey: {
      type: String,
      default: 'id'
    },
    selectedList: {
      type: Array,
      default: () => []
    },
    rowDisabledSelect: {
      type: Function,
      default: null
    }
  },
  data() {
    return {
      dialogVisible: false,
      loading: false,
      list: [],
      total: 0,
      innerSelectedList: [],
      innerSelectedRow: {},
      selectedRowKey: '',
      activeTab: 'select',
      queryParams: {
        pageNo: 1,
        pageSize: 10
      }
    }
  },
  methods: {
    getCellText(row, column) {
      if (!row || !column || !column.prop) return ''
      const value = column.prop.split('.').reduce((obj, key) => {
        return obj == null ? undefined : obj[key]
      }, row)
      if (value === undefined || value === null) return ''
      if (typeof column.formatter === 'function') {
        return column.formatter(row, column, value)
      }
      return value
    },

    syncSelectedRowKey() {
      const key = this.innerSelectedRow[this.rowKey]
      this.selectedRowKey = key === undefined || key === null || key === '' ? '' : key
    },

    selectSingleRow(row) {
      this.innerSelectedRow = row
      this.innerSelectedList = [row]
      this.selectedRowKey = row[this.rowKey]
    },

    clearSingleSelection() {
      this.innerSelectedRow = { [this.rowKey]: '' }
      this.innerSelectedList = []
      this.selectedRowKey = ''
    },

    onSingleRadioCellClick(row) {
      if (this.isRowDisabled(row)) return
      if (this.selectedRowKey !== '' && this.selectedRowKey == row[this.rowKey]) {
        this.clearSingleSelection()
      } else {
        this.selectSingleRow(row)
      }
    },

    async getList() {
      this.loading = true
      try {
        const data = await this.queryApi(this.queryParams)
        this.list = data.list || []
        this.total = data.total || 0
        if (this.multiple) {
          this.$nextTick(() => {
            this.list.forEach((row) => {
              const selected = this.innerSelectedList.some(
                (item) => item[this.rowKey] === row[this.rowKey]
              )
              this.$refs.tableRef.toggleRowSelection(row, selected && !this.isRowDisabled(row))
            })
          })
        }
      } finally {
        this.loading = false
      }
    },

    handleQuery() {
      this.queryParams.pageNo = 1
      this.getList()
    },

    handleReset() {
      const pageSize = this.queryParams.pageSize
      Object.keys(this.queryParams).forEach((key) => {
        if (key !== 'pageSize') {
          this.$set(this.queryParams, key, undefined)
        }
      })
      this.queryParams.pageNo = 1
      this.queryParams.pageSize = pageSize
      this.getList()
    },

    isRowDisabled(row) {
      if (typeof this.rowDisabledSelect === 'function') {
        return this.rowDisabledSelect(row)
      }
      return false
    },

    rowClassName({ row }) {
      return this.isRowDisabled(row) ? 'row_selected_disabled' : 'cursor-pointer'
    },

    handleRowClick(row) {
      if (this.isRowDisabled(row)) return

      if (this.multiple) {
        const index = this.innerSelectedList.findIndex(
          (item) => item[this.rowKey] === row[this.rowKey]
        )
        if (index > -1) {
          this.$refs.tableRef.toggleRowSelection(row, false)
          this.innerSelectedList.splice(index, 1)
        } else {
          this.innerSelectedList.push(row)
          this.$refs.tableRef.toggleRowSelection(row, true)
        }
      } else if (this.selectedRowKey !== '' && this.selectedRowKey == row[this.rowKey]) {
        this.clearSingleSelection()
      } else {
        this.selectSingleRow(row)
      }
    },

    handleSelect(selection, row) {
      if (this.isRowDisabled(row)) {
        this.$refs.tableRef.toggleRowSelection(row, false)
        return
      }
      const isSelected = selection.includes(row)
      if (isSelected) {
        if (!this.innerSelectedList.some((item) => item[this.rowKey] === row[this.rowKey])) {
          this.innerSelectedList.push(row)
        }
      } else {
        this.innerSelectedList = this.innerSelectedList.filter(
          (item) => item[this.rowKey] !== row[this.rowKey]
        )
      }
    },

    handleSelectAll(selection) {
      if (selection.length) {
        const currentSelectedList = this.list.filter(
          (row) => !this.isRowDisabled(row) &&
            !this.innerSelectedList.some((item) => item[this.rowKey] === row[this.rowKey])
        )
        this.innerSelectedList.push(...currentSelectedList)
        this.$nextTick(() => {
          this.list.forEach((row) => {
            if (this.isRowDisabled(row)) {
              this.$refs.tableRef.toggleRowSelection(row, false)
            }
          })
        })
      } else {
        this.innerSelectedList = this.innerSelectedList.filter(
          (row) => !this.list.some((selectRow) => selectRow[this.rowKey] === row[this.rowKey])
        )
      }
    },

    handleRemoveSelected(row) {
      if (this.multiple) {
        this.innerSelectedList = this.innerSelectedList.filter(
          (item) => item[this.rowKey] !== row[this.rowKey]
        )
        const currentRow = this.list.find((item) => item[this.rowKey] === row[this.rowKey])
        if (currentRow) {
          this.$refs.tableRef.toggleRowSelection(currentRow, false)
        }
      } else {
        this.clearSingleSelection()
      }
    },

    handleClearSelected() {
      if (this.multiple) {
        this.innerSelectedList = []
        this.$refs.tableRef.clearSelection()
      } else {
        this.clearSingleSelection()
      }
    },

    handleConfirm() {
      this.$emit('select', [...this.innerSelectedList])
      this.activeTab = 'select'
      this.dialogVisible = false
    },

    handleClose(done) {
      this.innerSelectedList = []
      this.innerSelectedRow = { [this.rowKey]: '' }
      this.selectedRowKey = ''
      this.activeTab = 'select'
      done()
    },

    open() {
      this.dialogVisible = true
      if (this.multiple) {
        this.innerSelectedList = [...(this.selectedList || [])]
        this.selectedRowKey = ''
      } else if (this.selectedList && this.selectedList.length) {
        this.innerSelectedRow = { ...this.selectedList[0] }
        this.innerSelectedList = [...this.selectedList]
        this.syncSelectedRowKey()
      } else {
        this.clearSingleSelection()
      }
      this.getList()
    }
  }
}
</script>

<style scoped>
.dialog-tabs {
  margin-bottom: 8px;
}

.query-form-wrap {
  margin-bottom: 12px;
}

.table-wrap {
  max-height: 420px;
  overflow: auto;
}

.pagination-wrap {
  display: flex;
  justify-content: center;
  margin-top: 16px;
}

.selected-toolbar {
  display: flex;
  justify-content: flex-end;
  margin-bottom: 12px;
}

.single-radio-cell {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
}

.dialog-footer {
  text-align: right;
}
</style>

<style>
.common-select-table-dialog .row_selected_disabled {
  cursor: not-allowed;
  color: #c0c4cc;
}

.common-select-table-dialog .cursor-pointer {
  cursor: pointer;
}
</style>
