<template>
  <el-select
    v-model="innerValue"
    :key="options.length"
    :filterable="filterable"
    :clearable="clearable"
    :disabled="disabled"
    :multiple="multiple"
    reserve-keyword
    :multiple-limit="multipleLimit"
    :filter-method="mESfilterMethod"
    :placeholder="placeholder"
    :collapse-tags="collapseTags"
    :allow-create="allowCreate"
    :default-first-option="defaultFirstOption"
    :class="{
      'is-disabled': disabled,
      'select-multiple': multiple
    }"
    :size="size"
    ref="select"
    @clear="clearSelect"
    @visible-change="mESvisibleChange"
    @change="handleChange"
  >
    <el-option
      v-for="item in visibleOptions"
      :key="item.key"
      :value="item.optionValue"
      :label="item.optionLabel"
      :disabled="item.o.disabled"
    >
      <template v-if="item.o.icon">
        <i
          class="iconfont"
          :class="item.o.dataSource ? 'field-fn-icon' : 'field-value-icon'"
          v-html="item.o.icon"
        ></i>
      </template>
      <template v-if="leftRightOptionsKey">
        <span class="ec-select-left">{{ item.o[leftRightOptionsKey.left] }}</span>
        <span class="ec-select-right">{{ item.o[leftRightOptionsKey.right] }}</span>
      </template>
      <template v-else>
        <el-tooltip
          v-if="item.o[_optionsKey.name]"
          :content="textOptionFlag ? item.o : item.o[_optionsKey.name]"
        >
          <span v-if="showOptionFullName">{{ item.o.name }}</span>
          <span v-else>{{ item.optionLabel }}</span>
        </el-tooltip>
        <span v-else>{{ item.optionLabel }}</span>
      </template>
      <span v-if="optionTipShow" class="option-tip">{{ optionTipText }}</span>
    </el-option>
  </el-select>
</template>

<script>
export default {
  name: 'EcSelect',
  props: {
    value: {
      default: undefined
    },
    multiple: {
      type: Boolean,
      default: false
    },
    multipleLimit: {
      type: Number,
      default: 0
    },
    options: {
      type: Array,
      default: () => []
    },
    optionsKey: {
      type: Object,
      default: () => ({})
    },
    filterable: {
      type: Boolean,
      default: false
    },
    clearable: {
      type: Boolean,
      default: false
    },
    disabled: {
      type: Boolean,
      default: false
    },
    size: {
      type: String,
      default: ''
    },
    placeholder: {
      type: String,
      default: '请选择'
    },
    collapseTags: {
      type: Boolean,
      default: false
    },
    allowCreate: {
      type: Boolean,
      default: false
    },
    defaultFirstOption: {
      type: Boolean,
      default: false
    },
    leftRightOptionsKey: {
      type: Object,
      default: null
    },
    textOption: {
      type: Boolean,
      default: false
    },
    showOptionFullName: {
      type: Boolean,
      default: false
    },
    defaultValueIndex: {
      type: [Number, String],
      default: undefined
    }
  },
  data () {
    return {
      keyword: ''
    }
  },
  computed: {
    _optionsKey () {
      return Object.assign({
        label: 'label',
        value: 'value'
      }, this.optionsKey)
    },
    innerValue: {
      get () {
        if (this.value instanceof Array) {
          return this.value.filter(r => r !== '')
        }
        return this.value
      },
      set (val) {
        this.$emit('input', val)
      }
    },
    textOptionFlag () {
      return this.textOption || this.allowCreate
    },
    optionTipText () {
      if (this.multiple && this.multipleLimit) {
        return `最多选择${this.multipleLimit}个`
      }
      return ''
    },
    optionTipShow () {
      const val = this.innerValue
      return this.multiple && this.multipleLimit && val && this.multipleLimit === val.length
    },
    visibleOptions () {
      return this.options
        .map((o, index) => ({ o, index }))
        .filter(({ o }) => this.optionShow(o))
        .map(({ o, index }) => ({
          o,
          key: index + '_' + this.keyword,
          optionValue: this.textOptionFlag ? o : o[this._optionsKey.value],
          optionLabel: this.textOptionFlag ? o : (o[this._optionsKey.label] || o.label || o.name)
        }))
    }
  },
  watch: {
    options: {
      handler (newValue, oldValue) {
        if (Number(this.defaultValueIndex) >= 0 && (oldValue?.length || newValue?.length)) {
          const index = Number(this.defaultValueIndex)
          if (this.options[index]) {
            const val = this.options[index][this._optionsKey.value]
            this.$emit('input', this.multiple ? [val] : val)
            this._unwatchDefaultOptions && this._unwatchDefaultOptions()
            this._unwatchDefaultOptions = null
          }
        }
      },
      immediate: true,
      deep: true
    }
  },
  mounted () {
    if (this.multiple) {
      if (!(this.value instanceof Array)) {
        this.$emit('input', [])
      }
    } else if (this.value === undefined) {
      this.$emit('input', '')
    }
  },
  beforeDestroy () {
    this._unwatchDefaultOptions = null
  },
  methods: {
    optionShow (option) {
      if (this.keyword) {
        if (this.allowCreate) {
          return option.indexOf(this.keyword) > -1
        }
        if (option[this._optionsKey.label]) {
          return option[this._optionsKey.label].indexOf(this.keyword) > -1
        }
        if (option[this._optionsKey.name]) {
          return option[this._optionsKey.name].indexOf(this.keyword) > -1
        }
        return true
      }
      return true
    },
    clearSelect () {
      this.$emit('clear')
    },
    mESfilterMethod (kw) {
      this.keyword = kw
    },
    mESvisibleChange (visible) {
      this.$emit(visible ? 'focus' : 'blur')
      this.$emit('visibleChange', visible)
      if (!visible) {
        setTimeout(() => {
          this.keyword = ''
        }, 300)
      }
    },
    handleChange (value) {
      this.$emit('change', value)
    }
  }
}
</script>

<style scoped>
.ec-select-left {
  float: left;
}

.ec-select-right {
  float: right;
  color: #8492a6;
  font-size: 13px;
}

.option-tip {
  float: right;
  color: #8492a6;
  font-size: 12px;
}
</style>
