<template>
  <div class="find-highlight-demo">
    <div class="demo-toolbar">
      <el-input
        v-model="findInputValue"
        placeholder="输入订单号关键字，Enter 搜索 / F3 下一个"
        clearable
        size="small"
        class="find-input"
        @keyup.enter.native="handleChangeFindList(true)"
        @input="handleFindInputChange"
      >
        <template slot="prepend">F3 搜索</template>
      </el-input>
      <el-tag v-if="findInputValue" size="small" type="info">
        匹配 {{ findResList.length }} 条
        <template v-if="findResList.length && findResRowId">
          · 当前第 {{ findListIndex + 1 }} 条
        </template>
      </el-tag>
      <el-button size="small" @click="handleChangeFindList(true)">搜索</el-button>
      <el-button size="small" type="primary" plain @click="handleFindList()">下一个 (F3)</el-button>
    </div>

    <div class="demo-tip">
      在订单列表中模糊搜索订单号，关键字黄色高亮，当前命中行橙色底色，按 F3 在匹配结果间循环跳转。
    </div>

    <el-table
      ref="orderTable"
      :data="orderTableList"
      border
      stripe
      height="420"
      :row-class-name="findHighlightRowClassName"
      highlight-current-row
    >
      <el-table-column prop="orderNo" label="订单号" min-width="160">
        <template slot-scope="{ row }">
          <span
            class="find-cell-wrap"
            :class="{ find_cell: row[findRowId] === findResRowId }"
            v-html="highlightKeyword(row.orderNo, findInputValue)"
          ></span>
        </template>
      </el-table-column>
      <el-table-column prop="productName" label="商品名称" min-width="160" show-overflow-tooltip />
      <el-table-column prop="orderStatus" label="订单状态" width="100" />
      <el-table-column prop="amount" label="实付(元)" width="100" align="right" />
      <el-table-column prop="orderTime" label="下单时间" width="160" />
    </el-table>

    <div class="mixin-code-hint">
      <div class="hint-title">Mixin 接入方式</div>
      <pre class="hint-code">import findHltMethods from '@/mixins/findHltMethods'

export default {
  mixins: [findHltMethods],
  data () {
    return {
      orderTableList: [],
      findListKey: 'orderTableList',
      findTableRef: 'orderTable',
      findMainKey: 'orderNo',
      findRowId: 'id',
      noFindMessage: '未找到匹配订单'
    }
  }
}</pre>
    </div>
  </div>
</template>

<script>
import findHltMethods from '@/mixins/findHltMethods'
import { highlightKeyword } from '@/utils/highlightKeyword'

const ORDER_STATUS = ['待付款', '待发货', '已发货', '已完成', '已关闭']
const PRODUCT_NAMES = [
  '无线蓝牙耳机 Pro', '极简运动水杯', '纯棉圆领 T 恤', '智能手环 S2',
  '北欧风台灯', '保湿面膜 10 片装', '机械键盘 K87', '不锈钢保温杯'
]

function buildMockList () {
  return Array.from({ length: 80 }, (_, i) => {
    const seq = String(i + 1).padStart(4, '0')
    return {
      id: i + 1,
      orderNo: `ORD202503${seq}`,
      productName: PRODUCT_NAMES[i % PRODUCT_NAMES.length],
      orderStatus: ORDER_STATUS[i % ORDER_STATUS.length],
      amount: (Math.random() * 800 + 49).toFixed(2),
      orderTime: `2025-03-${String((i % 28) + 1).padStart(2, '0')} ${String(9 + (i % 12)).padStart(2, '0')}:${String(i % 60).padStart(2, '0')}`
    }
  })
}

export default {
  name: 'FindHighlightTableDemo',
  mixins: [findHltMethods],
  data () {
    return {
      orderTableList: buildMockList(),
      findListKey: 'orderTableList',
      findTableRef: 'orderTable',
      findMainKey: 'orderNo',
      findRowId: 'id',
      isElTable: true,
      noFindMessage: '未找到匹配订单，请修改关键字后重试'
    }
  },
  methods: {
    highlightKeyword
  }
}
</script>

<style scoped>
.find-highlight-demo {
  padding: 12px 16px 24px;
}

.demo-toolbar {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 12px;
}

.find-input {
  width: 360px;
}

.demo-tip {
  font-size: 13px;
  color: #909399;
  margin-bottom: 12px;
  line-height: 1.6;
}

.mixin-code-hint {
  margin-top: 20px;
  padding: 12px 14px;
  background: #f5f7fa;
  border-radius: 4px;
  border: 1px solid #ebeef5;
}

.hint-title {
  font-size: 13px;
  font-weight: 600;
  color: #606266;
  margin-bottom: 8px;
}

.hint-code {
  margin: 0;
  font-size: 12px;
  line-height: 1.6;
  color: #303133;
  white-space: pre-wrap;
  font-family: Consolas, Monaco, monospace;
}
</style>

<style>
.hlt_kwd {
  background: #ff0;
  color: #000;
}

.find_cell {
  background: #ffb200;
  color: #000;
  padding: 0 2px;
  border-radius: 2px;
}

.find_cell .hlt_kwd {
  background: none;
}

.find-highlight-demo .find_row_current > td {
  background-color: #fdf6ec !important;
}

.find-cell-wrap {
  display: inline-block;
}
</style>
