/**
 * 列表 F3 / 输入框模糊搜索 + 高亮定位（参考 uniqhs-ui findHltMethods.js）
 *
 * 使用页面需配置：
 * - findMainKey: 搜索匹配字段，如 'steelPlateNumber'
 * - findListKey: 列表 data 字段名，如 'tableList'
 * - findTableRef: el-table ref 名，如 'dataTable'
 * - findRowId: 行唯一标识字段，默认与 findMainKey 相同，一般为 'id'
 * - isElTable: true（默认）使用 el-table 滚动定位
 * - noFindMessage: 未找到时的提示文案（可选）
 */
export default {
  data () {
    return {
      findInputValue: '',
      findResValue: '',
      findListIndex: -1,
      findResList: [],
      findResRowId: '',
      findRowId: '',
      isElTable: true,
      cacheWarnInputValue: '',
      findTimer: null
    }
  },
  created () {
    window.addEventListener('keydown', this.handleFindEvent)
    this.findRowId = this.findRowId || this.findMainKey
  },
  beforeDestroy () {
    window.removeEventListener('keydown', this.handleFindEvent)
    this.clearFindTimer()
  },
  activated () {
    window.addEventListener('keydown', this.handleFindEvent)
  },
  deactivated () {
    window.removeEventListener('keydown', this.handleFindEvent)
  },
  methods: {
    clearFindTimer () {
      if (this.findTimer) {
        clearTimeout(this.findTimer)
        this.findTimer = null
      }
    },

    /** 搜索框输入 / 回车 */
    handleChangeFindList (params) {
      this.clearFindTimer()
      this.findListIndex = -1
      this.findTimer = setTimeout(() => {
        this.handleFindList(params)
      }, 200)
    },

    /** F3 查找下一个 */
    handleFindEvent (event) {
      if (event.key === 'F3') {
        this.clearFindTimer()
        event.preventDefault()
        this.handleFindList()
      }
    },

    handleFindInputChange () {
      if (!this.findInputValue) {
        this.findResRowId = ''
        this.findResValue = ''
        this.findResList = []
        this.findListIndex = -1
      }
      this.handleChangeFindList()
    },

    handleFindList (doSearch) {
      this.$nextTick(() => {
        const list = this[this.findListKey] || []
        if (this.findResValue !== this.findInputValue || doSearch) {
          this.findListIndex = -1
          this.findResRowId = ''
          this.findResValue = this.findInputValue
          this.findResList = []
          if (this.findInputValue) {
            const kw = String(this.findInputValue)
            list.forEach((row) => {
              const fieldVal = row[this.findMainKey]
              if (fieldVal != null && String(fieldVal).indexOf(kw) > -1) {
                this.findResList.push(row)
              }
            })
          }
        }

        if (this.findResList.length) {
          let index = ++this.findListIndex
          if (index === this.findResList.length) {
            index = this.findListIndex = 0
          }
          const targetRow = this.findResList[index]
          this.findResRowId = targetRow[this.findRowId]
          this.scrollFindRowIntoView(targetRow)
        } else if (this.noFindMessage && this.findInputValue) {
          if (this.cacheWarnInputValue !== this.findInputValue) {
            this.$message.warning(this.noFindMessage)
            this.cacheWarnInputValue = this.findInputValue
          }
        }
      })
    },

    scrollFindRowIntoView (row) {
      if (!row || !this.isElTable) return
      const table = this.$refs[this.findTableRef]
      if (!table || !table.$el) return
      const rowId = row[this.findRowId]
      const el = table.$el.querySelector(`.table_row_${rowId}`)
      if (el) {
        el.scrollIntoView({ block: 'nearest' })
      }
    },

    /** el-table row-class-name 回调 */
    findHighlightRowClassName ({ row }) {
      const classes = [`table_row_${row[this.findRowId]}`]
      if (this.findResRowId !== '' && row[this.findRowId] === this.findResRowId) {
        classes.push('find_row_current')
      }
      return classes.join(' ')
    }
  }
}
