<template>
  <div class="component-showcase-page">
    <el-card shadow="never" class="intro-card">
      <div class="intro-title">组件封装 · Mixin · Element UI 扩展</div>
      <div class="intro-desc">
        个人前端能力演示：业务组件封装、列表 F3 搜索高亮、Element UI 补丁扩展等，Mock 数据采用通用电商场景。
      </div>
    </el-card>

    <el-tabs v-model="mainTab" type="border-card" class="main-tabs">
      <el-tab-pane label="组件封装" name="components">
        <el-tabs v-model="componentTab" class="sub-tabs">
          <!-- EcSelect -->
          <el-tab-pane label="EcSelect 下拉框封装" name="ec-select">
            <div class="demo-section">
              <div class="demo-block">
                <div class="demo-label">基础单选</div>
                <EcSelect
                  v-model="ecSingle"
                  :options="ecOptions"
                  placeholder="请选择订单状态"
                  clearable
                  filterable
                  style="width: 240px;"
                  @change="onEcChange('单选', $event)"
                />
                <span class="demo-value">当前值：{{ ecSingle || '--' }}</span>
              </div>

              <div class="demo-block">
                <div class="demo-label">多选 + 限制数量</div>
                <EcSelect
                  v-model="ecMultiple"
                  :options="ecOptions"
                  multiple
                  :multiple-limit="3"
                  collapse-tags
                  clearable
                  filterable
                  placeholder="最多选 3 项"
                  style="width: 320px;"
                />
                <span class="demo-value">当前值：{{ ecMultiple.length ? ecMultiple.join(', ') : '--' }}</span>
              </div>

              <div class="demo-block">
                <div class="demo-label">左右布局选项 + 自定义字段</div>
                <EcSelect
                  v-model="ecLibrary"
                  :options="ecLrOptions"
                  :options-key="{ label: 'name', value: 'code', name: 'name' }"
                  :left-right-options-key="{ left: 'left', right: 'right' }"
                  filterable
                  clearable
                  placeholder="请选择发货仓库"
                  style="width: 280px;"
                />
                <span class="demo-value">当前值：{{ ecLibrary || '--' }}</span>
              </div>

              <div class="demo-block">
                <div class="demo-label">defaultValueIndex 默认选中第一项</div>
                <EcSelect
                  v-model="ecDefault"
                  :options="ecOptions"
                  :default-value-index="0"
                  clearable
                  style="width: 240px;"
                />
                <span class="demo-value">当前值：{{ ecDefault || '--' }}</span>
              </div>
            </div>
          </el-tab-pane>

          <!-- DropdownSelect -->
          <el-tab-pane label="DropdownSelect 选择器封装" name="dropdown-select">
            <div class="demo-section">
              <div class="demo-block">
                <div class="demo-label">标题 + 悬停展开（defaultValueIndex）</div>
                <DropdownSelect
                  v-model="dropdownGroupId"
                  :dropdown-options="dropdownGroups"
                  :dropdown-item="{ label: 'groupName', value: 'id' }"
                  dropdown-name="商品频道"
                  :default-value-index="0"
                  @change="onDropdownChange"
                />
                <span class="demo-value">当前 id：{{ dropdownGroupId }}</span>
              </div>

              <div class="demo-block">
                <div class="demo-label">点击触发 + 自定义触发器（slot）</div>
                <DropdownSelect
                  :dropdown-options="importOptions"
                  :dropdown-item="{ label: 'label', value: 'event' }"
                  trigger="click"
                  @change="onImportChange"
                >
                  <el-button type="primary" plain size="small">
                    导入 <i class="el-icon-arrow-down el-icon--right"></i>
                  </el-button>
                </DropdownSelect>
                <span class="demo-value">最近操作：{{ importAction || '--' }}</span>
              </div>

              <div class="demo-block">
                <div class="demo-label">viewMode 只读展示</div>
                <DropdownSelect
                  v-model="dropdownGroupId"
                  :dropdown-options="dropdownGroups"
                  :dropdown-item="{ label: 'groupName', value: 'id' }"
                  dropdown-name="商品频道"
                  :view-mode="true"
                />
              </div>
            </div>
          </el-tab-pane>

          <!-- CommonSelectTableDialog -->
          <el-tab-pane label="CommonSelectTableDialog 表格弹窗" name="table-dialog">
            <div class="demo-section">
              <div class="demo-block demo-block-row">
                <el-button type="primary" @click="openMultiDialog">打开多选弹窗</el-button>
                <el-button @click="openSingleDialog">打开单选弹窗</el-button>
              </div>

              <div class="demo-block">
                <div class="demo-label">多选结果（{{ multiSelected.length }} 条）</div>
                <el-tag
                  v-for="item in multiSelected"
                  :key="'m-' + item.id"
                  size="small"
                  style="margin: 0 6px 6px 0;"
                >
                  {{ item.name }}
                </el-tag>
                <span v-if="!multiSelected.length" class="demo-value">暂无选择</span>
              </div>

              <div class="demo-block">
                <div class="demo-label">单选结果</div>
                <span class="demo-value">
                  {{ singleSelected.length ? singleSelected[0].name : '暂无选择' }}
                </span>
              </div>
            </div>

            <CommonSelectTableDialog
              ref="multiDialog"
              title="选择商品（多选）"
              width="800px"
              :multiple="true"
              :table-columns="tableColumns"
              :query-api="mockTableQueryApi"
              :selected-list="multiSelected"
              :row-disabled-select="rowDisabledSelect"
              @select="onMultiSelect"
            >
              <template slot="query" slot-scope="{ params }">
                <el-form-item label="商品名称">
                  <el-input
                    v-model="params.name"
                    placeholder="请输入商品名称"
                    clearable
                    style="width: 200px;"
                    @keyup.enter.native="triggerMultiQuery"
                  />
                </el-form-item>
                <el-form-item label="类目">
                  <el-select
                    v-model="params.category"
                    placeholder="全部"
                    clearable
                    style="width: 140px;"
                    @change="triggerMultiQuery"
                  >
                    <el-option label="数码" value="数码" />
                    <el-option label="服饰" value="服饰" />
                    <el-option label="家居" value="家居" />
                    <el-option label="美妆" value="美妆" />
                  </el-select>
                </el-form-item>
              </template>
              <template slot="category" slot-scope="{ row }">
                <el-tag size="mini" :type="categoryTagType(row.category)">{{ row.category }}</el-tag>
              </template>
            </CommonSelectTableDialog>

            <CommonSelectTableDialog
              ref="singleDialog"
              title="选择商品（单选）"
              width="800px"
              :multiple="false"
              :table-columns="tableColumns"
              :query-api="mockTableQueryApi"
              :selected-list="singleSelected"
              @select="onSingleSelect"
              :rowDisabledSelect="rowDisabledSelect"
            >
              <template slot="query" slot-scope="{ params }">
                <el-form-item label="商品名称">
                  <el-input
                    v-model="params.name"
                    placeholder="请输入商品名称"
                    clearable
                    style="width: 200px;"
                    @keyup.enter.native="triggerSingleQuery"
                  />
                </el-form-item>
              </template>
              <template slot="category" slot-scope="{ row }">
                <el-tag size="mini" :type="categoryTagType(row.category)">{{ row.category }}</el-tag>
              </template>
            </CommonSelectTableDialog>
          </el-tab-pane>
        </el-tabs>
      </el-tab-pane>

      <el-tab-pane label="Mixin 提取" name="mixins">
        <FindHighlightTableDemo />
      </el-tab-pane>

      <el-tab-pane label="组件功能扩展" name="element-patch">
        <ElementUiPatchDemo />
      </el-tab-pane>
    </el-tabs>
  </div>
</template>

<script>
import EcSelect from '@/components/EcSelect.vue'
import DropdownSelect from '@/components/DropdownSelect.vue'
import CommonSelectTableDialog from '@/components/CommonSelectTableDialog.vue'
import FindHighlightTableDemo from '@/components/FindHighlightTableDemo.vue'
import ElementUiPatchDemo from '@/components/ElementUiPatchDemo.vue'
import {
  EC_SELECT_OPTIONS,
  EC_SELECT_LR_OPTIONS,
  DROPDOWN_GROUP_OPTIONS,
  TABLE_DIALOG_COLUMNS,
  mockTableQueryApi
} from '@/utils/componentShowcaseMock'

export default {
  name: 'ComponentShowcase',
  components: {
    EcSelect,
    DropdownSelect,
    CommonSelectTableDialog,
    FindHighlightTableDemo,
    ElementUiPatchDemo
  },
  data () {
    return {
      mainTab: 'components',
      componentTab: 'ec-select',
      ecOptions: EC_SELECT_OPTIONS,
      ecLrOptions: EC_SELECT_LR_OPTIONS,
      ecSingle: '',
      ecMultiple: [],
      ecLibrary: '',
      ecDefault: '',
      dropdownGroups: DROPDOWN_GROUP_OPTIONS,
      dropdownGroupId: undefined,
      importOptions: [
        { event: 1, label: '从购物车导入' },
        { event: 2, label: '从收藏夹导入' }
      ],
      importAction: '',
      tableColumns: TABLE_DIALOG_COLUMNS,
      mockTableQueryApi,
      multiSelected: [],
      singleSelected: []
    }
  },
  methods: {
    onEcChange (label, val) {
      console.log('[EcSelect]', label, val)
    },
    onDropdownChange (item, val) {
      console.log('[DropdownSelect]', item, val)
    },
    onImportChange (item) {
      this.importAction = item.label
    },
    rowDisabledSelect (row) {
      return !row.onSale
    },
    categoryTagType (category) {
      const map = { 数码: '', 服饰: 'warning', 家居: 'success', 美妆: 'danger' }
      return map[category] || 'info'
    },
    openMultiDialog () {
      this.$refs.multiDialog.open()
    },
    openSingleDialog () {
      this.$refs.singleDialog.open()
    },
    triggerMultiQuery () {
      this.$refs.multiDialog.handleQuery()
    },
    triggerSingleQuery () {
      this.$refs.singleDialog.handleQuery()
    },
    onMultiSelect (list) {
      this.multiSelected = list
      this.$message.success(`已选择 ${list.length} 件商品`)
    },
    onSingleSelect (list) {
      this.singleSelected = list
      if (list.length) {
        this.$message.success(`已选择：${list[0].name}`)
      }
    }
  }
}
</script>

<style scoped>
.component-showcase-page {
  height: 100%;
  overflow: auto;
}

.intro-card {
  margin-bottom: 16px;
}

.intro-card >>> .el-card__body {
  padding: 14px 18px;
}

.intro-title {
  font-size: 16px;
  font-weight: 600;
  margin-bottom: 6px;
}

.intro-desc {
  font-size: 13px;
  color: #909399;
}

.main-tabs {
  min-height: 0;
}

.sub-tabs {
  padding: 8px 4px 0;
}

.demo-section {
  padding: 8px 12px 24px;
}

.demo-block {
  margin-bottom: 24px;
  padding-bottom: 20px;
  border-bottom: 1px dashed #ebeef5;
}

.demo-block:last-child {
  border-bottom: none;
}

.demo-block-row {
  display: flex;
  gap: 12px;
}

.demo-label {
  font-size: 14px;
  font-weight: 600;
  color: #303133;
  margin-bottom: 12px;
}

.demo-value {
  display: block;
  margin-top: 10px;
  font-size: 13px;
  color: #606266;
}
</style>
