/** 转义正则特殊字符 */
function escapeRegExp (str) {
  return String(str).replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
}

function escapeHtml (str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

/**
 * 关键字高亮（参考 uniqhs-ui main.js $highlightKeyword）
 * @returns {string} HTML 字符串，配合 v-html 使用
 */
export function highlightKeyword (value, keyword) {
  if (value == null || value === '') return ''
  const text = escapeHtml(value)
  if (!keyword) return text
  const kw = String(keyword).trim()
  if (!kw) return text
  const pattern = new RegExp(escapeRegExp(kw), 'gi')
  return text.replace(pattern, (match) => `<span class="hlt_kwd">${match}</span>`)
}
